#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char s[1005]; scanf("%s", s);
        int freq[26] = {0};
        for(int i=0;i<N;i++) freq[s[i]-'a']++;
        int possible = 0;
        for(int i=0;i<26;i++) if(freq[i]>=2){ possible = 1; break; }
        if(possible) printf("%d\n", N-2);
        else printf("-1\n");
    }
    return 0;
}

