        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            String s = br.readLine().trim();
            int[] freq = new int[26];
            for (int i = 0; i < N; i++) freq[s.charAt(i) - 'a']++;
            boolean ok = false;
            for (int f : freq) if (f >= 2) { ok = true; break; }
            if (ok) out.append(N - 2).append('\n');
            else out.append(-1).append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        s = next(it)
        freq = [0]*26
        for ch in s:
            freq[ord(ch)-97] += 1
        if any(f>=2 for f in freq):
            out_lines.append(str(N-2))
        else:
            out_lines.append(str(-1))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

